import sys
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions=1, replication_factor=1):
    try:
        admin_client.create_topics(
            [NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor)]
        )
        print(f"Topic {topic_name} created successfully.")
    except Exception as e:
        print(f"Failed to create topic {topic_name}: {e}")

def manage_partitions(admin_client, topic_name):
    try:
        partitions_info = admin_client.describe_topics([topic_name])
        current_partitions = partitions_info[topic_name].partition_assignment
        print(f"Current partitions for {topic_name}: {current_partitions}")
    except Exception as e:
        print(f"Failed to describe topic {topic_name}: {e}")

def configure_topic(admin_client, topic_name):
    try:
        admin_client.alter_configs(
            {topic_name: {'cleanup.policy': 'compact'}}
        )
        print(f"Topic {topic_name} configured successfully.")
    except Exception as e:
        print(f"Failed to configure topic {topic_name}: {e}")

def main():
    if len(sys.argv) != 2:
        print("Usage: python kafka_admin.py <topic_name>")
        sys.exit(1)

    topic_name = sys.argv[1]
    admin_client = KafkaAdminClient(bootstrap_servers='localhost:9092')

    create_topic(admin_client, topic_name)
    manage_partitions(admin_client, topic_name)
    configure_topic(admin_client, topic_name)

if __name__ == "__main__":
    main()